import React from 'react';

const faqs = [
  {
    question: 'Rezervasyonumu nasıl yapabilirim?',
    answer: 'Ana sayfadaki arama formunu kullanarak otel ve tarih seçimi yapabilir, ardından adımları takip ederek rezervasyonunuzu tamamlayabilirsiniz.'
  },
  {
    question: 'Rezervasyonumu nasıl iptal edebilirim?',
    answer: 'Hesabım > Rezervasyonlarım bölümünden ilgili rezervasyonu seçip iptal işlemini başlatabilirsiniz. İptal koşulları otelin politikasına göre değişiklik gösterebilir.'
  },
  {
    question: 'Ödeme yöntemleri nelerdir?',
    answer: 'Kredi kartı, banka kartı ve bazı otellerde varışta ödeme seçenekleri sunulmaktadır.'
  },
  {
    question: 'Destek ekibine nasıl ulaşabilirim?',
    answer: 'Aşağıdaki iletişim bilgilerinden bize ulaşabilirsiniz veya canlı destek penceresini kullanabilirsiniz.'
  },
];

const HelpCenterPage: React.FC = () => (
  <div className="container-custom py-16 max-w-3xl mx-auto">
    <h1 className="text-3xl font-bold mb-6">Help Center</h1>
    <p className="text-gray-700 mb-8">Find answers to common questions and get support for your reservations.</p>

    <section className="mb-10">
      <h2 className="text-2xl font-semibold mb-4">Sıkça Sorulan Sorular</h2>
      <div className="space-y-4">
        {faqs.map((faq, idx) => (
          <div key={idx} className="bg-gray-50 rounded-lg p-4 shadow-sm">
            <h3 className="font-semibold text-lg mb-1">{faq.question}</h3>
            <p className="text-gray-700">{faq.answer}</p>
          </div>
        ))}
      </div>
    </section>

    <section className="mb-10">
      <h2 className="text-2xl font-semibold mb-4">Bize Ulaşın</h2>
      <ul className="text-gray-700 space-y-2">
        <li><span className="font-medium">E-posta:</span> support@quadcore.com</li>
        <li><span className="font-medium">Telefon:</span> +90 555 123 45 67</li>
        <li><span className="font-medium">Canlı Destek:</span> Sağ alttaki sohbet penceresini kullanabilirsiniz.</li>
      </ul>
    </section>

    <section>
      <h2 className="text-2xl font-semibold mb-4">Hızlı Yardım</h2>
      <ul className="list-disc list-inside text-gray-700 space-y-1">
        <li>Rezervasyon adımlarını görmek için <span className="text-blue-600 underline cursor-pointer">buraya</span> tıklayın.</li>
        <li>İptal ve iade politikalarımızı incelemek için <span className="text-blue-600 underline cursor-pointer">buraya</span> tıklayın.</li>
        <li>Ödeme yöntemleri hakkında detaylı bilgi için <span className="text-blue-600 underline cursor-pointer">buraya</span> tıklayın.</li>
      </ul>
    </section>
  </div>
);

export default HelpCenterPage;
